+        // 1x1 grid but child at row=5, col=5
+        let layout = Layout::new()
+            .rows([Constraint::Fixed(3)])
+            .columns([Constraint::Fixed(3)])
+            .cell(rec, 5, 5);
+
+        let mut pool = GraphemePool::new();
+        let mut frame = Frame::new(10, 10, &mut pool);
